var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>침식파 억제 시스템이 마비됐다! 실험 도중 러처가 탈출했어!</color>","JPN":"<color=#ffd34c>侵食波抑制システムが麻痺した！　実験の途中にラッチャーが脱走したぞ！</color>","ENG":"<color=#ffd34c>The Corruption Inhibitor system is down! Lurcher escaped during the experiment!</color>","TWN":"<color=#ffd34c>侵蝕波抑制系統癱瘓！實驗體在實驗過程中逃跑了！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>프리하트 박사는 어디에 있나! 셰퍼드가 사라졌다!</color>","JPN":"<color=#ffd34c>プラハト博士はどこにいる！　シェパードが消えた！</color>","ENG":"<color=#ffd34c>Where's Dr. Freeheart?! Shepherd's gone!</color>","TWN":"<color=#ffd34c>普立哈特博士在哪裡！牧羊犬不見了！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>모든 출입문을 봉쇄해! 박사를 찾아!</color>","JPN":"<color=#ffd34c>すべての出入口を封鎖しろ！　博士を捜せ！</color>","ENG":"<color=#ffd34c>Block off all the exits! Find Dr. Freeheart!</color>","TWN":"<color=#ffd34c>封鎖所有出入口！找到博士！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>침식파장이 뒤섞인 비정상 차원이동 에너지 관측! 놈이 격리시설을 벗어나려고 합니다!</color>","JPN":"<color=#ffd34c>侵食波状が混ざった異常次元移動エネルギーを観測！　やつが隔離施設から出ようとしています！</color>","ENG":"<color=#ffd34c>Detecting an abnormal reading of dimensional jump energy mixed with Corruption rays! It is trying to escape the quarantine facility!</color>","TWN":"<color=#ffd34c>觀測到侵蝕波長中摻雜的異常次元移動能量！他正試圖逃離隔離設施！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>EM펄스 및 레벨3 블랙매터 사용을 허가한다! 시설 전체를 다운시키는 한이 있어도 놈이 벗어나는 건 막아!</color>","JPN":"<color=#ffd34c>EMパルスおよびレベル3のブラックマターの使用を許可する！　施設全体をダウンさせても、やつをここから出すな！</color>","ENG":"<color=#ffd34c>Permitting the use of EM pulses and Level 3 dark matter! Stop it from escaping even if it means shutting down the entire facility!</color>","TWN":"<color=#ffd34c>允許使用EM脈衝和3級暗物質！阻止他逃跑，哪怕摧毀整個設施！</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…찾았다.","JPN":"……見つけた。","ENG":"...Shepherd found it.","TWN":"……牧羊犬找到了。"},"stage":{"bg":"WAREHOUSE_02","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"눈에 안 띄고, 시원한 곳.","JPN":"誰の目にも付かない、涼しいところ。","ENG":"An inconspicuous and cool place.","TWN":"這裡不太起眼，但很涼爽。"},"stage":{"bg":"WAREHOUSE_02","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"얼음이 하나도 없어.","JPN":"氷が一つもない。","ENG":"There is no ice.","TWN":"不過這裡沒有冰塊。"},"stage":{"bg":"WAREHOUSE_02","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그래도… 여기서 얌전히 기다려야 해. <color=#ffd34c>약속</color>했으니까.","JPN":"でも……ここでじっと待たないと。<color=#ffd34c>約束</color>したから。","ENG":"But still... Shepherd has to wait here. Because Shepherd <color=#ffd34c>promised</color>.","TWN":"但……牧羊犬必須耐心。因為<color=#ffd34c>約定</color>好了。"},"stage":{"bg":"WAREHOUSE_02","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WAREHOUSE_02","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"러처도… 안전한 곳 찾았으면 좋겠다.","JPN":"ラッチャーも……安全なところが見つかればいいな。","ENG":"Shepherd also hopes... that Lurcher finds a safe place too.","TWN":"獵犬……也能找到一個安全的地方就好了。"},"stage":{"bg":"WAREHOUSE_02","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>세포보존시스템 활성화. 스프리건 인자 집속부 급속동결 시작.</color>","JPN":"<color=#ffd34c>細胞保存システム活性化。スプリガン因子集束部の急速凍結開始。</color>","ENG":"<color=#ffd34c>Activating cell preservation system. Starting rapid freezing of Spriggan Factors in concentration.</color>","TWN":"<color=#ffd34c>細胞保存系統啟動。守護者因子集束，冷凍開始。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>동결해제 시점… 명령권자의 접촉이 있을 때까지.</color>","JPN":"<color=#ffd34c>凍結解除時点……命令権者との接触があるまで。</color>","ENG":"<color=#ffd34c>Unfreezing only when... coming into contact with the commander.</color>","TWN":"<color=#ffd34c>解凍日期為……直到指揮官聯繫為止。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>사고 프로세스를 중지하고 휴면모드로 전환합니다.</color>","JPN":"<color=#ffd34c>思考プロセスを中止して休眠モードに切り替えます。</color>","ENG":"<color=#ffd34c>Suspending thought process and going into hibernation mode.</color>","TWN":"<color=#ffd34c>中斷思維程式，進入睡眠模式。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>외부로부터 강력한 전자기 펄스를 감지.</color>","JPN":"<color=#ffd34c>外部から強力な電磁気パルスを感知。</color>","ENG":"<color=#ffd34c>Detecting strong electromagnetic pulses from the outside.</color>","TWN":"<color=#ffd34c>感應到來自外部的強電磁脈衝。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>충격으로 비활성화된 세포보존기능을 복원합니다.</color>","JPN":"<color=#ffd34c>衝撃により非活性化された細胞保存機能を復元します。</color>","ENG":"<color=#ffd34c>Restoring the cell preservation function disabled by the shock.</color>","TWN":"<color=#ffd34c>恢復因衝擊而關閉的細胞保存功能。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시스템을 복원하는 동안, 사고 프로세스가 일시적으로 기능할 수 있습니다.</color>","JPN":"<color=#ffd34c>システムを復元する間、思考プロセスを一時的に機能できます。</color>","ENG":"<color=#ffd34c>While the system is restoring, thought process will be temporarily functional.</color>","TWN":"<color=#ffd34c>系統恢復期間，思維程式將會暫時失效。</color>"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_CAMERA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"여긴… 어디지?","JPN":"ここは……どこ？","ENG":"What is this place…?","TWN":"這個地方……是哪裡？"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"날 부르는 목소리가 들려…","JPN":"シェパードを呼ぶ声がする……","ENG":"Shepherd hears someone calling...","TWN":"有一個聲音在呼喚牧羊犬……"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"그리운 풍경… 그리운 목소리…","JPN":"懐かしい風景……懐かしい声……","ENG":"A nostalgic scenery... and voice...","TWN":"讓人懷念的風景……讓人懷念的聲音……"},"stage":{"bg":"WHITE","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"운이 좋았네. 한겨울에 딸기를 팔다니 말이야.","JPN":"運がよかったわね。真冬にイチゴを売ってるなんて。","ENG":"We were lucky. Finding someone who sells strawberries in the middle of winter.","TWN":"今天運氣很不錯呢。冬天還能遇見賣草莓的。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마가 해준 스무디가 그렇게 맛있어?","JPN":"お母さんのスムージー、そんなに美味しい？","ENG":"Do you like the smoothie I made you that much?","TWN":"媽媽做的冰沙有那麼好吃嗎？"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"차가워. 이게 스무디라는 거구나.","JPN":"冷たい。これがスムージーなんだ。","ENG":"It's cold. So this is what a smoothie is.","TWN":"好冰。這就是冰沙啊。"},"stage":{"bg":"DORMITORY_2","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};